890: 			return fmt.Errorf("no version priority set for %#v", *apiGroupInfo)
891: 		}
892: 		// Do not register empty group or empty version.  Doing so claims /apis/ for the wrong entity to be returned.
893: 		// Catching these here places the error  much closer to its origin
894: 		if len(apiGroupInfo.PrioritizedVersions[0].Group) == 0 {
895: 			return fmt.Errorf("cannot register handler with an empty group for %#v", *apiGroupInfo)
896: 		}
897: 		if len(apiGroupInfo.PrioritizedVersions[0].Version) == 0 {
898: 			return fmt.Errorf("cannot register handler with an empty version for %#v", *apiGroupInfo)
899: 		}
900: 	}
901: 
902: 	openAPIModels, err := s.getOpenAPIModels(APIGroupPrefix, apiGroupInfos...)
903: 	if err != nil {
904: 		return fmt.Errorf("unable to get openapi models: %v", err)
905: 	}
906: 
907: 	for _, apiGroupInfo := range apiGroupInfos {
908: 		if err := s.installAPIResources(APIGroupPrefix, apiGroupInfo, openAPIModels); err != nil {
909: 			return fmt.Errorf("unable to install api resources: %v", err)
910: 		}
911: 
912: 		// setup discovery
913: 		// Install the version handler.
914: 		// Add a handler at /apis/<groupName> to enumerate all versions supported by this group.
915: 		apiVersionsForDiscovery := []metav1.GroupVersionForDiscovery{}
916: 		for _, groupVersion := range apiGroupInfo.PrioritizedVersions {
917: 			// Check the config to make sure that we elide versions that don't have any resources
918: 			if len(apiGroupInfo.VersionedResourcesStorageMap[groupVersion.Version]) == 0 {
919: 				continue
920: 			}
