922: 				GroupVersion: groupVersion.String(),
923: 				Version:      groupVersion.Version,
924: 			})
925: 		}
926: 		preferredVersionForDiscovery := metav1.GroupVersionForDiscovery{
927: 			GroupVersion: apiGroupInfo.PrioritizedVersions[0].String(),
928: 			Version:      apiGroupInfo.PrioritizedVersions[0].Version,
929: 		}
930: 		apiGroup := metav1.APIGroup{
931: 			Name:             apiGroupInfo.PrioritizedVersions[0].Group,
932: 			Versions:         apiVersionsForDiscovery,
933: 			PreferredVersion: preferredVersionForDiscovery,
934: 		}
